#!/usr/bin/env bash
# Multiplexer for multiple Claude Code sessions — install
# Generated by tools/generate_scripts.py (ADR-030 contract).
# Do not edit directly; modify the body in tools/generate_scripts.py
# and re-run `python3 tools/generate_scripts.py`.
set -Eeuo pipefail

. "$SINDRI_HELPERS_SH"
sindri::init

# `WANT` aliases the target version env var so existing per-component
# bodies that reference `$WANT` keep reading naturally.
WANT="$SINDRI_COMPONENT_VERSION"

info "Setting up Claude Code session multiplexer…"
require tmux
require claude

MUX_BIN="$HOME/.local/bin/claude-mux"
mkdir -p "$HOME/.local/bin"

cat > "$MUX_BIN" <<'MUXEOF'
#!/usr/bin/env bash
# claude-mux — open multiple Claude Code sessions in a tmux layout
set -e
SESSION="${1:-claude}"
tmux new-session -d -s "$SESSION" -x 220 -y 50 2>/dev/null || true
tmux split-window -h -t "$SESSION"
tmux split-window -v -t "$SESSION:0.0"
tmux select-pane -t "$SESSION:0.0" && tmux send-keys "claude" Enter
tmux select-pane -t "$SESSION:0.1" && tmux send-keys "claude" Enter
tmux select-pane -t "$SESSION:0.2"
tmux attach-session -t "$SESSION"
MUXEOF
chmod +x "$MUX_BIN"

info "claude-mux installed at $MUX_BIN"
info "Usage: claude-mux [session-name]"

# ADR-030: signal a successful run that did real work. The skip path
# (`sindri::at_version … && exit 0`) emits `change:false` and exits
# before reaching here.
sindri::emit phase-complete '"change":true'
